    let none = option::none<NoDrop>().or!(option::some(NoDrop {}));
    let some = option::some(NoDrop {}).or!(option::some(NoDrop {}));

    assert!(none.is_some());
    assert!(some.is_some());

    let NoDrop {} = none.destroy_some();
    let NoDrop {} = some.destroy_some();
