#[test_only]
module std::vector_tests;

use std::unit_test::assert_eq;

public struct R has store {}
public struct Droppable has drop {}
public struct NotDroppable {}

#[test]
fun test_singleton_contains() {
    assert_eq!(vector[0u64][0], 0);
    assert_eq!(vector[true][0], true);
    assert_eq!(vector[@0x1][0], @0x1);
}

#[test]
fun test_singleton_len() {
    assert_eq!(vector[0u64].length(), 1);
    assert_eq!(vector[true].length(), 1);
    assert_eq!(vector[@0x1].length(), 1);
}

#[test]
fun test_empty_is_empty() {
    assert!(vector<u64>[].is_empty());
}

#[test]
fun append_empties_is_empty() {
    let mut v1 = vector<u64>[];
    let v2 = vector<u64>[];
    v1.append(v2);
    assert!(v1.is_empty());
}

#[test]
fun append_singletons() {
    let mut v1 = vector[0u64];
    let v2 = vector[1];
    v1.append(v2);
    assert_eq!(v1.length(), 2);
    assert_eq!(v1[0], 0);
    assert_eq!(v1[1], 1);
}

#[test]
fun append_respects_order_empty_lhs() {
    let mut v1 = vector[];
    let mut v2 = vector[];
    v2.push_back(0u64);
    v2.push_back(1);
    v2.push_back(2);
    v2.push_back(3);
    v1.append(v2);
    assert!(!v1.is_empty());
    assert_eq!(v1.length(), 4);
    assert_eq!(v1[0], 0);
    assert_eq!(v1[1], 1);
    assert_eq!(v1[2], 2);
    assert_eq!(v1[3], 3);
}

#[test]
fun append_respects_order_empty_rhs() {
    let mut v1 = vector[];
    let v2 = vector[];
    v1.push_back(0u64);
    v1.push_back(1);
    v1.push_back(2);
    v1.push_back(3);
    v1.append(v2);
    assert!(!v1.is_empty());
    assert_eq!(v1.length(), 4);
    assert_eq!(v1[0], 0);
    assert_eq!(v1[1], 1);
    assert_eq!(v1[2], 2);
    assert_eq!(v1[3], 3);
}

#[test]
fun append_respects_order_nonempty_rhs_lhs() {
    let mut v1 = vector[];
    let mut v2 = vector[];
    v1.push_back(0);
    v1.push_back(1);
    v1.push_back(2);
    v1.push_back(3);
    v2.push_back(4);
    v2.push_back(5);
    v2.push_back(6);
    v2.push_back(7);
    v1.append(v2);
    assert!(!v1.is_empty());
    assert_eq!(v1.length(), 8);
    let mut i = 0;
    while (i < 8) {
        assert_eq!(v1[i], i);
        i = i + 1;
    }
}

