fun vector_contains() {
    let mut vec = vector[];
    assert!(!vec.contains(&0u64));

    vec.push_back(0);
    assert!(vec.contains(&0));
    assert!(!vec.contains(&1));

    vec.push_back(1);
    assert!(vec.contains(&0));
    assert!(vec.contains(&1));
    assert!(!vec.contains(&2));

    vec.push_back(2);
    assert!(vec.contains(&0));
    assert!(vec.contains(&1));
    assert!(vec.contains(&2));
    assert!(!vec.contains(&3));
}

