#[test_only]
fun test_natives_with_type<T>(mut x1: T, mut x2: T): (T, T) {
    let mut v = vector[];
    assert_eq!(v.length(), 0);
    v.push_back(x1);
    assert_eq!(v.length(), 1);
    v.push_back(x2);
    assert_eq!(v.length(), 2);
    v.swap(0, 1);
    x1 = v.pop_back();
    assert_eq!(v.length(), 1);
    x2 = v.pop_back();
    assert_eq!(v.length(), 0);
    v.destroy_empty();
    (x1, x2)
}

#[test]
