#[test]
fun insertion_sort_by_macro() {
    let mut arr = UNSORTED_100;
    arr.insertion_sort_by!(|a, b| *a <= *b);
    assert!(arr.is_sorted_by!(|a, b| *a <= *b));

    let mut arr = UNSORTED_50;
    arr.insertion_sort_by!(|a, b| *a < *b);
    assert!(arr.is_sorted_by!(|a, b| *a <= *b));

    let mut arr = UNSORTED_40;
    arr.insertion_sort_by!(|a, b| *a < *b);
    assert!(arr.is_sorted_by!(|a, b| *a <= *b));

    let mut arr = UNSORTED_30;
    arr.insertion_sort_by!(|a, b| *a < *b);
    assert!(arr.is_sorted_by!(|a, b| *a <= *b));
}

