    let mut bag = bag::new(scenario.ctx());
    // add fields
    bag.add(b"hello", 0u64);
    bag.add(1u64, 1u8);
    // check they exist
    assert!(bag.contains_with_type<vector<u8>, u64>(b"hello"));
    assert!(bag.contains_with_type<u64, u8>(1));
