    let sk = x"42258dcda14cf111c602b8971b8cc843e91e46ca905151c02744a6b017e69316";

    // Test with Keccak256 hash
    let sig = ecdsa_k1::secp256k1_sign(&sk, &msg, 0, true);
    assert!(pk == ecdsa_k1::secp256k1_ecrecover(&sig, &msg, 0));

