fun test_withdrawal_split_join(owner: address, l1: u128, l2: u128, l3: u128) {
    let l1 = l1 as u256;
    let l2 = l2 as u256;
    let l3 = l3 as u256;
    // ensure l1 > l2 + l3
    let mut w1 = create_withdrawal<TestToken>(owner, l1 + l2 + l3);
    let w2 = w1.split(l2);
    let w3 = w1.split(l3);

