        let request = policy::new_request(fresh_id(ctx), 10_000, fresh_id(ctx));
        policy.confirm_request(request);

        wrapup(policy, cap, ctx);
    }

    #[test]
    #[expected_failure(abort_code = sui::transfer_policy::EIllegalRule)]
