        assert!(math::sqrt(i * i) == i);
        i = i + 1;
    };
    let mut i = 0xFFFFFFFFF;
    while (i < 0xFFFFFFFFF + 1) {
        assert!(math::sqrt_u128(i * i) == i);
        i = i + 1;
    }
