// initial value OR whether it is equal to the nearest lower
// number that does.
fun test_imperfect_sqrt() {
    let mut i = 1;
    let mut prev = 1;
    while (i <= 1000) {
        let root = math::sqrt(i);

        assert!(i == root * root || root == prev);

        prev = root;
        i = i + 1;
    }
}

