public fun update_tenant_id(
    character: &mut Character,
    admin_acl: &AdminACL,
    tenant: String,
    ctx: &TxContext,
) {
    admin_acl.verify_sponsor(ctx);
    assert!(tenant.length() > 0, ETenantEmpty);
    let current_id = in_game_id::item_id(&character.key);
