        assert_eq!(location::x(coords_ref), expected_x);
        assert_eq!(location::y(coords_ref), expected_y);
        assert_eq!(location::z(coords_ref), expected_z);
        ts::return_shared(registry);
    };
    ts::end(ts);
}

