        );

        let inv_ref = df::borrow<ID, Inventory>(&storage_unit.id, character_id);
        assert_eq!(inv_ref.item_quantity(AMMO_TYPE_ID), 8);
        assert_eq!(inv_ref.item_volume(AMMO_TYPE_ID), AMMO_VOLUME);
