public(package) macro fun test_try_as_u128<$T>($max: $T) {
    assert_eq!((0: $T).try_as_u128(), option::some(0));
    assert_eq!((1: $T).try_as_u128(), option::some(1));
    assert_eq!(
        (0xFFFF_FFFF_FFFF_FFFF_FFFF_FFFF_FFFF_FFFF: $T).try_as_u128(),
