        let mut deny_list: deny_list::DenyList = scenario.take_shared();
        assert!(coin::deny_list_contains<COIN_TESTS>(&deny_list, @200));
        coin::deny_list_remove(&mut deny_list, &mut deny_cap, @200, scenario.ctx());
        assert!(!coin::deny_list_contains<COIN_TESTS>(&deny_list, @200));
