fun test_g1_ops() {
    let id = bls12381::g1_identity();
    let g = bls12381::g1_generator();

    assert!(group_ops::equal(&id, &bls12381::g1_sub(&g, &g)));
    assert!(group_ops::equal(&id, &bls12381::g1_sub(&id, &id)));
