    let (policy, policy_cap) = test::get_policy(ctx);

    kiosk.place(&owner_cap, asset);

    assert!(kiosk.has_item(item_id));
    let asset = kiosk.take(&owner_cap, item_id);
    assert!(!kiosk.has_item(item_id));

