#[test]
fun test_shuffle() {
    let mut scenario = test_scenario::begin(@0x0);

    random::create_for_testing(scenario.ctx());
    scenario.next_tx(@0x0);

    let mut random_state = scenario.take_shared<Random>();
    random_state.update_randomness_state_for_testing(
        0,
        x"1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F1F",
        scenario.ctx(),
    );

    let mut gen = random_state.new_generator(scenario.ctx());
    let mut v: vector<u16> = vector[0, 1, 2, 3, 4];
    gen.shuffle(&mut v);
    assert!(v.length() == 5);
    let mut i: u16 = 0;
    while (i < 5) {
        assert!(v.contains(&i));
        i = i + 1;
    };

    // check that numbers indeed eventaually move to all positions
    loop {
        gen.shuffle(&mut v);
        if ((v[4] == 1u16)) break;
    };
    loop {
        gen.shuffle(&mut v);
        if ((v[0] == 2u16)) break;
    };

    let mut v: vector<u32> = vector[];
    gen.shuffle(&mut v);
    assert!(v.length() == 0);

    let mut v: vector<u32> = vector[321];
    gen.shuffle(&mut v);
    assert!(v.length() == 1);
    assert!(v[0] == 321u32);

    test_scenario::return_shared(random_state);
    scenario.end();
}

#[test]
fun random_tests_in_range() {
    let mut scenario = test_scenario::begin(@0x0);

