#[test]
fun smoke() {
    let mut m = vec_map::empty();
    10u64.do!(|i| {
        let k = i + 2;
        let v = i + 5;
        m.insert(k, v);
    });
    assert!(!m.is_empty());
    assert_eq!(m.length(), 10);
    // make sure the elements are as expected in all of the getter APIs we expose
    10u64.do!(|i| {
        let k = i + 2;
        assert!(m.contains(&k));
