","dependencies/world/sources/primitives/inventory.move":"// This module implements the logic of inventory operations such as depositing, withdrawing and transferring items between inventories.
//
// Items have two forms, inspired by Sui's `Coin` / `Balance` split:
//
// - **`ItemEntry`** (at-rest) — lightweight `copy, drop, store` dynamic field data inside `Inventory`.
// - **`Item`** (in-transit) — a Sui object created on withdrawal, consumed on deposit.
//   Carries a `parent_id` so the parent assembly can verify origin on deposit.
//   Also carries location data for more robust proximity validation in the future.
//
// # Bridging
//
// The game server is the trusted bridge between game and chain.
//
// - **Game → Chain (mint):** The game server calls an admin-gated function to mint
//   items directly into an on-chain inventory. Restricted by admin capability.
// - **Chain → Game (burn):** Burns the on-chain item and emits an event; the game
//   server listens to recreate the item in-game. Restricted by proximity proof.
//
// # Volume
//
// Volume per `type_id` is static: the first mint/deposit sets the volume,
// and subsequent operations use the stored volume for capacity accounting.
// Incoming volume mismatches are silently ignored.
//
// TODO: volume is currently assumed static per type_id — incoming volume mismatches
// are silently ignored. Volume may change over time and will need proper handling.
module world::inventory;

use std::string::String;
use sui::{clock::Clock, event, vec_map::{Self, VecMap}};
use world::{
    access::ServerAddressRegistry,
    character::Character,
    in_game_id::TenantItemId,
    location::{Self, Location}
};

// === Errors ===
#[error(code = 0)]
const ETypeIdEmpty: vector<u8> = b"Type ID cannot be empty";
#[error(code = 1)]
const EInventoryInvalidCapacity: vector<u8> = b"Inventory Capacity cannot be 0";
#[error(code = 2)]
const EInventoryInsufficientCapacity: vector<u8> = b"Insufficient capacity in the inventory";
#[error(code = 3)]
const EItemDoesNotExist: vector<u8> = b"Item not found";
#[error(code = 4)]
const EInventoryInsufficientQuantity: vector<u8> = b"Insufficient quantity in inventory";
#[error(code = 6)]
const ETypeIdMismatch: vector<u8> = b"Item type_id must match for join operation";
#[error(code = 7)]
const ESplitQuantityInvalid: vector<u8> =
    b"Split quantity must be greater than 0 and less than item quantity";

// === Structs ===

// On-chain inventory that tracks items by `type_id`.
//
// Each `type_id` maps to a single `ItemEntry`. `used_capacity` is the running
// total of `volume * quantity` across every entry. It must never exceed
// `max_capacity`.
//
// The inventory struct is a dynamic field entry attached to its host assembly, so it does not have a key.
// Note: Gas cost is high, lookup and insert complexity for VecMap is o(n). The alternative is to use a Table and a separate Vector.
// Currently, VecMap seems to be the best fit for this use case but can be revisited if performance becomes an issue.
public struct Inventory has store {
    max_capacity: u64,
    used_capacity: u64,
    items: VecMap<u64, ItemEntry>,
}

// At-rest item data stored inside an `Inventory`.
//
// Has `copy, drop, store` — no UID, no object overhead. Think of this as the
// `Balance` to `Item`'s `Coin`.
//
// Does **not** store location or parent_id — these are just-in-time metadata injected by the
// parent layer (e.g. StorageUnit) when creating a transit `Item` on withdrawal.
//
// Note: we assume that volume is constant for a given type_id.
public struct ItemEntry has copy, drop, store {
    tenant: String,
    type_id: u64,
    item_id: u64,
    volume: u64,
    quantity: u32,
}

/// Transit form of an item — created on withdraw, consumed on deposit.
///
/// Carries a fresh UID so it can be transferred between inventories as a
/// first-class Sui object. Destroyed (UID deleted) when deposited.
///
/// `parent_id` is the object ID of the assembly this item was withdrawn from
/// (e.g. a StorageUnit). The parent layer checks this on deposit to ensure items
/// return to their origin.
public struct Item has key, store {
    id: UID,
    parent_id: ID,
    tenant: String,
    type_id: u64,
    item_id: u64,
    volume: u64,
    quantity: u32,
    location: Location,
}

// === Events ===
public struct ItemMintedEvent has copy, drop {
    assembly_id: ID,
    assembly_key: TenantItemId,
    character_id: ID,
    character_key: TenantItemId,
    item_id: u64,
    type_id: u64,
    quantity: u32,
}

public struct ItemBurnedEvent has copy, drop {
    assembly_id: ID,
    assembly_key: TenantItemId,
    character_id: ID,
    character_key: TenantItemId,
    item_id: u64,
    type_id: u64,
    quantity: u32,
}

public struct ItemDepositedEvent has copy, drop {
    assembly_id: ID,
    assembly_key: TenantItemId,
    character_id: ID,
    character_key: TenantItemId,
    item_id: u64,
    type_id: u64,
    quantity: u32,
}

public struct ItemWithdrawnEvent has copy, drop {
    assembly_id: ID,
    assembly_key: TenantItemId,
    character_id: ID,
    character_key: TenantItemId,
    item_id: u64,
    type_id: u64,
    quantity: u32,
}

public struct ItemDestroyedEvent has copy, drop {
    assembly_id: ID,
    assembly_key: TenantItemId,
    item_id: u64,
    type_id: u64,
    quantity: u32,
}

// === View Functions ===
/// Sui object ID of this transit `Item` (`Item` is `key`; `Inventory` is not an object).
public fun id(item: &Item): ID {
    object::id(item)
}

public fun tenant(item: &Item): String {
    item.tenant
}

public fun contains_item(inventory: &Inventory, type_id: u64): bool {
    inventory.items.contains(&type_id)
}

/// Returns the location hash from the transit Item (metadata only, not used for
/// deposit validation — parent_id is used instead).
public fun get_item_location_hash(item: &Item): vector<u8> {
    item.location.hash()
}

/// Returns the object ID of the assembly this item was withdrawn from.
public fun parent_id(item: &Item): ID {
    item.parent_id
}

public fun max_capacity(inventory: &Inventory): u64 {
    inventory.max_capacity
}

public fun type_id(item: &Item): u64 {
    item.type_id
}

public fun quantity(item: &Item): u32 {
    item.quantity
}

// === Package Functions ===

/// Merge `other` into this entry. Both must have the same `type_id`.
public(package) fun join(entry: &mut ItemEntry, other: ItemEntry) {
    assert!(entry.type_id == other.type_id, ETypeIdMismatch);
    entry.quantity = entry.quantity + other.quantity;
}

public(package) fun create(max_capacity: u64): Inventory {
    assert!(max_capacity != 0, EInventoryInvalidCapacity);

    Inventory {
        max_capacity,
        used_capacity: 0,
        items: vec_map::empty(),
    }
}

// Mints items into inventory (Game → Chain bridge).
// Package-scoped — only callable from within the `world` module.
// This ensures that minting only happens from trusted sources.
// If the type_id already exists, increases quantity in place.
// Otherwise, creates a new entry.
public(package) fun mint_items(
    inventory: &mut Inventory,
    assembly_id: ID,
    assembly_key: TenantItemId,
    character: &Character,
    tenant: String,
    item_id: u64,
    type_id: u64,
    volume: u64,
    quantity: u32,
) {
    assert!(type_id != 0, ETypeIdEmpty);

    // Use stored volume when the type_id already exists (volume is static per type_id).
    let effective_volume = if (inventory.items.contains(&type_id)) {
        inventory.items[&type_id].volume
    } else {
        volume
    };

    let req_capacity = calculate_volume(effective_volume, quantity);
    let remaining = inventory.max_capacity - inventory.used_capacity;
    assert!(req_capacity <= remaining, EInventoryInsufficientCapacity);
    inventory.used_capacity = inventory.used_capacity + req_capacity;

    let emit_item_id = if (inventory.items.contains(&type_id)) {
        let entry = &mut inventory.items[&type_id];
        entry.quantity = entry.quantity + quantity;
        entry.item_id
    } else {
        inventory.items.insert(type_id, ItemEntry { tenant, type_id, item_id, volume, quantity });
        item_id
    };

    event::emit(ItemMintedEvent {
        assembly_id,
        assembly_key,
        character_id: character.id(),
        character_key: character.key(),
        item_id: emit_item_id,
        type_id,
        quantity,
    });
}

// TODO: remove proximity proof check as it will be handled in the parent module
public(package) fun burn_items_with_proof(
    inventory: &mut Inventory,
    assembly_id: ID,
    assembly_key: TenantItemId,
    character: &Character,
    server_registry: &ServerAddressRegistry,
    location: &Location,
    location_proof: vector<u8>,
    type_id: u64,
    quantity: u32,
    clock: &Clock,
    ctx: &mut TxContext,
) {
    location::verify_proximity_proof_from_bytes(
        server_registry,
        location,
        location_proof,
        clock,
        ctx,
    );
    burn_items(inventory, assembly_id, assembly_key, character, type_id, quantity);
}

// Deposits a transit `Item` back into the inventory.
//
// Destroys the `Item`'s UID, extracts its data into an `ItemEntry`, and either
// joins into the existing entry or creates a new one.
//
// Parent-ID validation is **not** done here — that is the responsibility of the
// parent layer (e.g. storage_unit.move) which has access to the assembly's object ID.
public(package) fun deposit_item(
    inventory: &mut Inventory,
    assembly_id: ID,
    assembly_key: TenantItemId,
    character: &Character,
    item: Item,
) {
    let Item { id, parent_id: _, tenant, type_id, item_id, volume, quantity, location } = item;
    id.delete();
    location.remove();

    // Use stored volume when the type_id already exists (volume is static per type_id).
    let effective_volume = if (inventory.items.contains(&type_id)) {
        inventory.items[&type_id].volume
    } else {
        volume
    };

    let req_capacity = calculate_volume(effective_volume, quantity);
    let remaining = inventory.max_capacity - inventory.used_capacity;
    assert!(req_capacity <= remaining, EInventoryInsufficientCapacity);
    inventory.used_capacity = inventory.used_capacity + req_capacity;

    let entry = ItemEntry { tenant, type_id, item_id, volume, quantity };

    let dep_item_id = if (inventory.items.contains(&type_id)) {
        let existing = &mut inventory.items[&type_id];
        let existing_item_id = existing.item_id;
        existing.join(entry);
        existing_item_id
    } else {
        inventory.items.insert(type_id, entry);
        item_id
    };

    event::emit(ItemDepositedEvent {
        assembly_id,
        assembly_key,
        character_id: character.id(),
        character_key: character.key(),
        item_id: dep_item_id,
        type_id,
        quantity,
    });
}

// Withdraws items from the inventory and wraps them into a transit `Item`.
//
// `location_hash` is injected by the parent layer (e.g. StorageUnit) — it is not
// stored in `ItemEntry` since it is just-in-time metadata for the transit `Item`.
//
// `assembly_id` doubles as the `parent_id` on the resulting `Item`.
public(package) fun withdraw_item(
    inventory: &mut Inventory,
    assembly_id: ID,
    assembly_key: TenantItemId,
    character: &Character,
    type_id: u64,
    quantity: u32,
    location_hash: vector<u8>,
    ctx: &mut TxContext,
): Item {
    assert!(inventory.items.contains(&type_id), EItemDoesNotExist);
    assert!(quantity > 0, ESplitQuantityInvalid);

    let entry = &inventory.items[&type_id];
    assert!(entry.quantity >= quantity, EInventoryInsufficientQuantity);
    let volume = entry.volume;
    let item_id = entry.item_id;
    let tenant = entry.tenant;

    let capacity_freed = calculate_volume(volume, quantity);
    inventory.used_capacity = inventory.used_capacity - capacity_freed;

    if (entry.quantity == quantity) {
        inventory.items.remove(&type_id);
    } else {
        let entry_mut = &mut inventory.items[&type_id];
        entry_mut.quantity = entry_mut.quantity - quantity;
    };

    event::emit(ItemWithdrawnEvent {
        assembly_id,
        assembly_key,
        character_id: character.id(),
        character_key: character.key(),
        item_id,
        type_id,
        quantity,
    });

    Item {
        id: object::new(ctx),
        parent_id: assembly_id,
        tenant,
        type_id,
        item_id,
        volume,
        quantity,
        location: location::attach(location_hash),
    }
}

/// Destroys the inventory, emitting an `ItemDestroyedEvent` per entry.
public(package) fun delete(inventory: Inventory, assembly_id: ID, assembly_key: TenantItemId) {
    let Inventory {
        mut items,
        ..,
    } = inventory;

    // Burn items one by one
    while (!items.is_empty()) {
        let (_, entry) = items.pop();
        event::emit(ItemDestroyedEvent {
            assembly_id,
            assembly_key,
            item_id: entry.item_id,
            type_id: entry.type_id,
            quantity: entry.quantity,
        });
    };
    items.destroy_empty();
}

// FUTURE: transfer items between inventory, eg: inventory to inventory on-chain.
// This needs location proof and distance to enforce digital physics.
// public fun transfer_items() {}

// === Private Functions ===

// Burns items from on-chain inventory (Chain → Game bridge).
//
// Reduces quantity (or removes the entry entirely if fully burned) and frees
// the corresponding capacity.
// Emits an `ItemBurnedEvent` for the game server to recreate the item in-game (when necessary).
fun burn_items(
    inventory: &mut Inventory,
    assembly_id: ID,
    assembly_key: TenantItemId,
    character: &Character,
    type_id: u64,
    quantity: u32,
) {
    assert!(inventory.items.contains(&type_id), EItemDoesNotExist);

    let entry = &inventory.items[&type_id];
    assert!(entry.quantity >= quantity, EInventoryInsufficientQuantity);
    let item_id = entry.item_id;
    let volume = entry.volume;

    let capacity_freed = calculate_volume(volume, quantity);
    inventory.used_capacity = inventory.used_capacity - capacity_freed;

    if (entry.quantity == quantity) {
        inventory.items.remove(&type_id);
    } else {
        let entry_mut = &mut inventory.items[&type_id];
        entry_mut.quantity = entry_mut.quantity - quantity;
    };

    event::emit(ItemBurnedEvent {
        assembly_id,
        assembly_key,
        character_id: character.id(),
        character_key: character.key(),
        item_id,
        type_id,
        quantity,
    });
}

/// Total capacity consumed by a single entry: `volume * quantity`.
fun calculate_volume(volume: u64, quantity: u32): u64 {
    volume * (quantity as u64)
}

// === Test Functions ===
#[test_only]
public fun remaining_capacity(inventory: &Inventory): u64 {
    inventory.max_capacity - inventory.used_capacity
}

#[test_only]
public fun used_capacity(inventory: &Inventory): u64 {
    inventory.used_capacity
}

#[test_only]
public fun item_quantity(inventory: &Inventory, type_id: u64): u32 {
    inventory.items[&type_id].quantity
}

#[test_only]
public fun item_volume(inventory: &Inventory, type_id: u64): u64 {
    inventory.items[&type_id].volume
}

/// Number of unique type_ids in the inventory.
#[test_only]
public fun inventory_item_length(inventory: &Inventory): u64 {
    inventory.items.length()
}

#[test_only]
public fun burn_items_test(
    inventory: &mut Inventory,
    assembly_id: ID,
    assembly_key: TenantItemId,
    character: &Character,
    type_id: u64,
    quantity: u32,
) {
    burn_items(inventory, assembly_id, assembly_key, character, type_id, quantity);
}

// Mocking without deadline
#[test_only]
public fun burn_items_with_proof_test(
    inventory: &mut Inventory,
    assembly_id: ID,
    assembly_key: TenantItemId,
    character: &Character,
    server_registry: &ServerAddressRegistry,
    location: &Location,
    location_proof: vector<u8>,
    type_id: u64,
    quantity: u32,
    ctx: &mut TxContext,
) {
    location::verify_proximity_proof_from_bytes_without_deadline(
        server_registry,
        location,
        location_proof,
        ctx,
    );
    burn_items(inventory, assembly_id, assembly_key, character, type_id, quantity);
}
","dependencies/world/sources/primitives/location.move":"/// Location verification module for validating proximity using signature verification.
///
/// This module provides location hash storage and validation functionality that can be
/// attached to any game structure (e.g., inventory, item, ship, etc.). It enables
/// proximity-based access control by verifying that a player is in proximity
/// to a structure before allowing interactions.
module world::location;

use std::string::String;
use sui::{bcs, clock::Clock, event, table::{Self, Table}};
use world::{access::{Self, AdminACL, ServerAddressRegistry}, in_game_id::TenantItemId, sig_verify};

// === Errors ===
#[error(code = 0)]
const ENotInProximity: vector<u8> = b"Structures are not in proximity";
#[error(code = 1)]
const EInvalidHashLength: vector<u8> = b"Invalid length for SHA256";
#[error(code = 2)]
const EUnverifiedSender: vector<u8> = b"The proof was not signed for the sender";
#[error(code = 3)]
const EInvalidLocationHash: vector<u8> = b"Invalid location hash";
#[error(code = 4)]
const EUnauthorizedServer: vector<u8> = b"Message signed by unauthorized server";
#[error(code = 5)]
const ESignatureVerificationFailed: vector<u8> = b"Signature verification failed";
#[error(code = 6)]
const EDeadlineExpired: vector<u8> = b"Deadline has expired";
#[error(code = 7)]
const EOutOfRange: vector<u8> = b"Invalid Distance";

// === Structs ===

/// Represents a location hash attached to a game structure.
/// The location_hash should be a Poseidon2 hash of the location coordinates.
/// See: https://docs.sui.io/references/framework/sui_sui/poseidon
public struct Location has store {
    location_hash: vector<u8>,
}

/// A signed message containing location proof information.
/// This message is signed by an authorized server to prove that a player
/// is within proximity of a target structure.
///
/// # Arguments
/// * `server_address` - The address of the server that signed the message
/// * `player_address` - The address of the player to whom the proof is issued
/// * `source_structure_id` - The ID of the structure initiating the interaction
/// * `source_location_hash` - The hash of the source structure's location. eg: ship/gate location
/// * `target_structure_id` - The ID of the structure the player wants to interact with
/// * `target_location_hash` - The hash of the target structure's location
/// * `distance` - The distance between player and target structure
/// * `data` - Additional data field
/// * `deadline_ms` - expiration timestamp in milliseconds
public struct LocationProofMessage has drop {
    server_address: address,
    player_address: address,
    source_structure_id: ID,
    source_location_hash: vector<u8>,
    target_structure_id: ID,
    target_location_hash: vector<u8>,
    distance: u64,
    data: vector<u8>,
    deadline_ms: u64,
}

/// A complete location proof containing the message and its signature.
public struct LocationProof has drop {
    message: LocationProofMessage,
    signature: vector<u8>,
}

public struct LocationRegistry has key {
    id: UID,
    locations: Table<ID, Coordinates>,
}

// Revealed location data for one assembly. Queryable on-chain. solarsystem is u64; x,y,z as String allow negative/float.
// x,y,z are stored as strings to support negative values, dapps can parse to number.
public struct Coordinates has copy, drop, store {
    solarsystem: u64,
    x: String, // to support negative values
    y: String, // to support negative values
    z: String, // to support negative values
}

public struct LocationRevealedEvent has copy, drop {
    assembly_id: ID,
    assembly_key: TenantItemId,
    type_id: u64,
    owner_cap_id: ID,
    location_hash: vector<u8>,
    solarsystem: u64,
    x: String,
    y: String,
    z: String,
}

// === Public Functions ===

public fun create_location_proof(
    server_address: address,
    player_address: address,
    source_structure_id: ID,
    source_location_hash: vector<u8>,
    target_structure_id: ID,
    target_location_hash: vector<u8>,
    distance: u64,
    data: vector<u8>,
    deadline_ms: u64,
    signature: vector<u8>,
): LocationProof {
    let message = LocationProofMessage {
        server_address,
        player_address,
        source_structure_id,
        source_location_hash,
        target_structure_id,
        target_location_hash,
        distance,
        data,
        deadline_ms,
    };

    LocationProof {
        message,
        signature,
    }
}

/// Verify that a server-signed proof attesting a player is near a structure
/// This function gets `proof` LocationProof as struct
public fun verify_proximity(
    location: &Location,
    proof: LocationProof,
    server_registry: &ServerAddressRegistry,
    clock: &Clock,
    ctx: &mut TxContext,
) {
    let LocationProof { message, signature } = proof;

    validate_proof_message(&message, location, server_registry, ctx.sender());

    let message_bytes = bcs::to_bytes(&message);
    assert!(is_deadline_valid(message.deadline_ms, clock), EDeadlineExpired);
    assert!(
        sig_verify::verify_signature(
            message_bytes,
            signature,
            message.server_address,
        ),
        ESignatureVerificationFailed,
    )
}

/// Verify that a server-signed proof attesting a player is in proximity the structure.
/// This function gets `proof_bytes` the LocationProof as bytes
public fun verify_proximity_proof_from_bytes(
    server_registry: &ServerAddressRegistry,
    location: &Location,
    proof_bytes: vector<u8>,
    clock: &Clock,
    ctx: &mut TxContext,
) {
    let (message, signature) = unpack_proof(proof_bytes);

    validate_proof_message(&message, location, server_registry, ctx.sender());

    let message_bytes = bcs::to_bytes(&message);
    assert!(is_deadline_valid(message.deadline_ms, clock), EDeadlineExpired);
    assert!(
        sig_verify::verify_signature(
            message_bytes,
            signature,
            message.server_address,
        ),
        ESignatureVerificationFailed,
    )
}

/// Verify that a server-signed proof attesting two structures are under a certain distance.
public fun verify_distance(
    location: &Location,
    server_registry: &ServerAddressRegistry,
    proof_bytes: vector<u8>,
    max_distance: u64,
    ctx: &mut TxContext,
) {
    let (message, signature) = unpack_proof(proof_bytes);

    validate_proof_message(&message, location, server_registry, ctx.sender());

    let message_bytes = bcs::to_bytes(&message);
    assert!(message.distance <= max_distance, EOutOfRange);
    assert!(
        sig_verify::verify_signature(
            message_bytes,
            signature,
            message.server_address,
        ),
        ESignatureVerificationFailed,
    )
}

/// Verifies if two locations are in proximity based on their hashes.
///
/// It is used for ephemeral storage operations where both inventory are in the same location
public fun verify_same_location(location_a_hash: vector<u8>, location_b_hash: vector<u8>) {
    assert!(location_a_hash == location_b_hash, ENotInProximity);
}

// === View Functions ===
public fun id(registry: &LocationRegistry): ID {
    object::id(registry)
}

public fun hash(location: &Location): vector<u8> {
    location.location_hash
}

public fun get_location(registry: &LocationRegistry, assembly_id: ID): Option<Coordinates> {
    if (registry.locations.contains(assembly_id)) {
        option::some(*registry.locations.borrow(assembly_id))
    } else {
        option::none()
    }
}

public fun solarsystem(data: &Coordinates): u64 {
    data.solarsystem
}

public fun x(data: &Coordinates): String {
    data.x
}

public fun y(data: &Coordinates): String {
    data.y
}

public fun z(data: &Coordinates): String {
    data.z
}

// === Admin Functions ===

public fun update(
    location: &mut Location,
    admin_acl: &AdminACL,
    location_hash: vector<u8>,
    ctx: &TxContext,
) {
    admin_acl.verify_sponsor(ctx);
    assert!(location_hash.length() == 32, EInvalidHashLength);
    location.location_hash = location_hash;
}

/// Low-level: records coordinates (solarsystem u64; x,y,z strings for negative/float). No admin check.
public(package) fun reveal_location(
    registry: &mut LocationRegistry,
    assembly_id: ID,
    assembly_key: TenantItemId,
    type_id: u64,
    owner_cap_id: ID,
    location_hash: vector<u8>,
    solarsystem: u64,
    x: String,
    y: String,
    z: String,
) {
    set_location_internal(
        registry,
        assembly_id,
        assembly_key,
        type_id,
        owner_cap_id,
        location_hash,
        solarsystem,
        x,
        y,
        z,
    );
}

// === Package Functions ===

public(package) fun attach(location_hash: vector<u8>): Location {
    assert!(location_hash.length() == 32, EInvalidHashLength);
    Location {
        location_hash,
    }
}

public(package) fun remove(location: Location) {
    let Location { .. } = location;
}

// === Private Functions ===

/// Validates the location proof message against the provided location and context.
fun validate_proof_message(
    message: &LocationProofMessage,
    expected_location: &Location,
    server_registry: &ServerAddressRegistry,
    sender: address,
) {
    assert!(
        access::is_authorized_server_address(server_registry, message.server_address),
        EUnauthorizedServer,
    );
    assert!(message.player_address == sender, EUnverifiedSender);
    assert!(message.target_location_hash == expected_location.location_hash, EInvalidLocationHash);
}

/// Deserializes a LocationProof from bytes using BCS peel functions.
///
/// BCS serializes structs field-by-field, so we peel each field in order:
/// 1. LocationProofMessage fields (server_address, player_address, etc.)
/// 2. signature (vector<u8>)
fun unpack_proof(proof_bytes: vector<u8>): (LocationProofMessage, vector<u8>) {
    let mut bcs_data = bcs::new(proof_bytes);

    // Deserialize LocationProofMessage fields
    let server_address = bcs_data.peel_address();
    let player_address = bcs_data.peel_address();
    let source_structure_id = object::id_from_address(bcs_data.peel_address());
    let source_location_hash = bcs_data.peel_vec!(|bcs| bcs.peel_u8());
    let target_structure_id = object::id_from_address(bcs_data.peel_address());
    let target_location_hash = bcs_data.peel_vec!(|bcs| bcs.peel_u8());
    let distance = bcs_data.peel_u64();
    let data = bcs_data.peel_vec!(|bcs| bcs.peel_u8());
    let deadline_ms = bcs_data.peel_u64();

    // Deserialize signature
    let signature = bcs_data.peel_vec!(|bcs| bcs.peel_u8());

    let message = LocationProofMessage {
        server_address,
        player_address,
        source_structure_id,
        source_location_hash,
        target_structure_id,
        target_location_hash,
        distance,
        data,
        deadline_ms,
    };
    (message, signature)
}

fun is_deadline_valid(deadline_ms: u64, clock: &Clock): bool {
    let current_time_ms = clock.timestamp_ms();
    deadline_ms > current_time_ms
}

fun set_location_internal(
    registry: &mut LocationRegistry,
    assembly_id: ID,
    assembly_key: TenantItemId,
    type_id: u64,
    owner_cap_id: ID,
    location_hash: vector<u8>,
    solarsystem: u64,
    x: String,
    y: String,
    z: String,
) {
    let data = Coordinates {
        solarsystem,
        x,
        y,
        z,
    };
    if (registry.locations.contains(assembly_id)) {
        registry.locations.remove(assembly_id);
    };
    registry.locations.add(assembly_id, data);
    event::emit(LocationRevealedEvent {
        assembly_id,
        assembly_key,
        type_id,
        owner_cap_id,
        location_hash,
        solarsystem,
        x,
        y,
        z,
    });
}

fun init(ctx: &mut TxContext) {
    transfer::share_object(LocationRegistry {
        id: object::new(ctx),
        locations: table::new(ctx),
    });
}

// === Test Functions ===

/// Verifies a location proof without deadline validation (test-only).
///
/// This function is provided for testing purposes because Move does not have
/// built-in signing functionality. Messages signed offline need to be hardcoded
/// in tests, which means deadlines will always expire unless we set a never-expiring
/// deadline. This function bypasses deadline validation for testing convenience.
#[test_only]
public fun verify_proximity_without_deadline(
    server_registry: &ServerAddressRegistry,
    location: &Location,
    proof: LocationProof,
    ctx: &mut TxContext,
): bool {
    let LocationProof { message, signature } = proof;

    validate_proof_message(&message, location, server_registry, ctx.sender());

    let message_bytes = bcs::to_bytes(&message);
    sig_verify::verify_signature(
        message_bytes,
        signature,
        message.server_address,
    )
}

#[test_only]
public fun verify_proximity_proof_from_bytes_without_deadline(
    server_registry: &ServerAddressRegistry,
    location: &Location,
    proof_bytes: vector<u8>,
    ctx: &mut TxContext,
) {
    let (message, signature) = unpack_proof(proof_bytes);
    validate_proof_message(&message, location, server_registry, ctx.sender());

    let message_bytes = bcs::to_bytes(&message);
    assert!(
        sig_verify::verify_signature(
            message_bytes,
            signature,
            message.server_address,
        ),
        ESignatureVerificationFailed,
    );
}

#[test_only]
public fun init_for_testing(ctx: &mut TxContext) {
    init(ctx);
}
