public fun swap_ammo_for_lens_extension<T: key>(
    storage_unit: &mut StorageUnit,
    owner_cap: &OwnerCap<T>,
    character: &Character,
    ctx: &mut TxContext,
) {
    // Step 1: withdraws lens from storage unit (extension access)
    let lens = storage_unit.withdraw_item<SwapAuth>(
        character,
        SwapAuth {},
        LENS_TYPE_ID,
        LENS_QUANTITY,
