            AMMO_TYPE_ID,
            AMMO_QUANTITY,
            ts.ctx(),
        );
        storage_unit.deposit_item<SwapAuth>(&character, item, SwapAuth {}, ts.ctx());
        assert_eq!(
            storage_unit.item_quantity(storage_unit.owner_cap_id(), AMMO_TYPE_ID),
            AMMO_QUANTITY,
        );
        ts::return_shared(storage_unit);
        ts::return_shared(character);
    };

    ts::end(ts);
}

