        assert_eq!(inv_ref.item_volume(AMMO_TYPE_ID), AMMO_VOLUME);
        assert_eq!(inv_ref.used_capacity(), 1000);
        assert_eq!(inv_ref.inventory_item_length(), 1);

        ts::return_shared(storage_unit);
        ts::return_shared(character);
    };
    ts::end(ts);
}

