fun create_character(ts: &mut ts::Scenario, user: address, item_id: u32): ID {
    ts::next_tx(ts, admin());
    {
        let character_id = {
            let admin_acl = ts::take_shared<AdminACL>(ts);
            let mut registry = ts::take_shared<ObjectRegistry>(ts);
